# Updated files:

## App.tsx

1.  添加了 `handleDownload` 函数，用于生成并下载包含完整对话状态的 JSON 文件。
2.  更新了 `handleFileUpload` 函数，使其能智能识别并导入两种格式：简单的消息数组（原始数据）或 完整的 Conversation 对象（包含评估、高亮和评论的存档数据）。
3.  在编辑器视图的头部导航栏中添加了下载按钮。

```tsx
// ... existing code ...
  const handleDownload = () => {
    if (!currentConversation) return;

    const jsonString = JSON.stringify(currentConversation, null, 2);
    const blob = new Blob([jsonString], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');

    // Create a safe filename
    const safeTitle = currentConversation.title.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    link.href = url;
    link.download = `${safeTitle}_evaluated.json`;
    document.body.appendChild(link);
    link.click();

    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (e) => {
      try {
        const json = JSON.parse(e.target?.result as string);

        let newConv: Conversation;

        // Support for importing the Full Conversation Export (with highlights, comments, evaluation)
        if (json.messages && Array.isArray(json.messages)) {
             newConv = {
                 ...json,
                 // Regenerate ID to avoid conflicts if importing the same file twice, 
                 // but keep the content/title/evaluation intact.
                 id: `conv-${Date.now()}`, 
                 createdAt: json.createdAt || Date.now()
             };
        } 
        // Support for Raw Message Array (legacy/external tools)
        else if (Array.isArray(json)) {
            newConv = {
              id: `conv-${Date.now()}`,
              title: file.name.replace('.json', '') || 'Uploaded Conversation',
              messages: json.map((m: any, idx: number) => ({
                id: `msg-${Date.now()}-${idx}`,
                role: m.role || Role.USER,
                content: m.content || "",
                comments: []
              })),
              createdAt: Date.now()
            };
        } else {
             throw new Error("Unknown format");
        }

        setConversations(prev => [newConv, ...prev]);
        setCurrentConversation(newConv);
        setViewState('editor');
      } catch (err) {
        setError("Invalid JSON format. Expected a Conversation object or an Array of messages.");
      }
    };
    reader.readAsText(file);
    // Reset value so the same file can be selected again if needed
    event.target.value = '';
  };
